import React, { useEffect } from 'react';

interface ToastProps {
  message: string;
  type: 'success' | 'error' | 'info' | 'warning';
  onClose: () => void;
}

export default function Toast({ message, type, onClose }: ToastProps) {
  useEffect(() => {
    const t = setTimeout(onClose, 4000);
    return () => clearTimeout(t);
  }, [onClose]);

  const colors: any = {
    success: { bg: '#059669', icon: '✓' },
    error:   { bg: '#dc2626', icon: '✕' },
    warning: { bg: '#d97706', icon: '⚠' },
    info:    { bg: '#3b82f6', icon: 'ℹ' },
  };
  const c = colors[type];

  return (
    <div style={{
      position: 'fixed', bottom: 28, right: 28, zIndex: 9999,
      display: 'flex', alignItems: 'center', gap: 12,
      background: '#1a1a2e', color: '#fff',
      padding: '14px 20px', borderRadius: 14,
      boxShadow: '0 8px 32px rgba(26,26,46,0.3)',
      animation: 'slideIn .3s ease',
      minWidth: 280, maxWidth: 380,
    }}>
      <style>{`@keyframes slideIn { from { opacity:0; transform:translateX(40px); } to { opacity:1; transform:translateX(0); } }`}</style>
      <div style={{ width: 32, height: 32, borderRadius: 8, background: c.bg, display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 15, fontWeight: 700, flexShrink: 0 }}>
        {c.icon}
      </div>
      <div style={{ flex: 1, fontSize: 13, lineHeight: 1.4 }}>{message}</div>
      <button onClick={onClose} style={{ background: 'rgba(255,255,255,0.1)', border: 'none', color: '#fff', width: 24, height: 24, borderRadius: 6, cursor: 'pointer', fontSize: 12, flexShrink: 0 }}>✕</button>
    </div>
  );
}
